const response = $input.first().json;
const sites = response.data || [];
return sites.map(site => ({ json: site }));

const site = $('Route by Motion').item.json;
const sub = $('Get Stripe Subscription').first().json;
const invoicesResp = $input.first().json;

let plan_name = '';
let plan_rate = 0;
if (sub && sub.items && sub.items.data && sub.items.data.length > 0) {
  const item = sub.items.data[0];
  plan_name = (item.price && item.price.nickname) || (item.plan && item.plan.nickname) || '';
  plan_rate = item.price ? (item.price.unit_amount || 0) / 100 : 0;
}

const now = Date.now();
const thirtyDaysAgo = Math.floor((now - 30 * 24 * 60 * 60 * 1000) / 1000);

let monthly_revenue = 0;
let lifetime_revenue = 0;
let days_past_due = 0;
let billing_health = 'healthy';

const invoices = (invoicesResp && invoicesResp.data) || [];

for (const inv of invoices) {
  if (inv.status === 'paid') {
    lifetime_revenue += (inv.amount_paid || 0) / 100;
    if (inv.created >= thirtyDaysAgo) {
      monthly_revenue += (inv.amount_paid || 0) / 100;
    }
  }
  if (inv.status === 'open' && inv.due_date) {
    const dueDateSec = inv.due_date;
    const nowSec = Math.floor(now / 1000);
    if (dueDateSec < nowSec) {
      const overdueDays = Math.floor((nowSec - dueDateSec) / 86400);
      if (overdueDays > days_past_due) {
        days_past_due = overdueDays;
      }
      billing_health = 'past_due';
    }
  }
}

if (monthly_revenue === 0 && plan_rate > 0) {
  monthly_revenue = plan_rate;
}

const annual_revenue = monthly_revenue * 12;

return [{
  json: {
    site_registry: site.name,
    billing_motion: site.billing_motion || 'self_serve',
    stripe_customer_id: site.stripe_customer_id || '',
    stripe_subscription_id: site.stripe_subscription_id || '',
    erpnext_customer_name: site.erpnext_customer_name || '',
    erpnext_subscription_name: site.erpnext_subscription_name || '',
    plan_name: plan_name,
    monthly_revenue: monthly_revenue,
    annual_revenue: annual_revenue,
    lifetime_revenue: lifetime_revenue,
    billing_health: billing_health,
    days_past_due: days_past_due,
    churn_risk_score: 0,
    last_usage_review: null,
    upsell_candidate: 0,
    notes: null
  }
}];

const site = $('Route by Motion').item.json;
const invoicesResp = $input.first().json;

const now = new Date();
const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
const thirtyDaysAgoStr = thirtyDaysAgo.toISOString().slice(0, 10);

let monthly_revenue = 0;
let lifetime_revenue = 0;
let days_past_due = 0;
let billing_health = 'healthy';

const invoices = (invoicesResp && invoicesResp.data) || [];

for (const inv of invoices) {
  lifetime_revenue += (inv.grand_total || 0);

  if (inv.posting_date >= thirtyDaysAgoStr) {
    monthly_revenue += (inv.grand_total || 0);
  }

  if (inv.outstanding_amount > 0 && inv.due_date) {
    const dueDate = new Date(inv.due_date);
    if (dueDate < now) {
      const overdueDays = Math.floor((now - dueDate) / (1000 * 60 * 60 * 24));
      if (overdueDays > days_past_due) {
        days_past_due = overdueDays;
      }
      billing_health = 'past_due';
    }
  }
}

const annual_revenue = monthly_revenue * 12;

return [{
  json: {
    site_registry: site.name,
    billing_motion: site.billing_motion || 'managed_account',
    stripe_customer_id: site.stripe_customer_id || '',
    stripe_subscription_id: site.stripe_subscription_id || '',
    erpnext_customer_name: site.erpnext_customer_name || '',
    erpnext_subscription_name: site.erpnext_subscription_name || '',
    plan_name: '',
    monthly_revenue: monthly_revenue,
    annual_revenue: annual_revenue,
    lifetime_revenue: lifetime_revenue,
    billing_health: billing_health,
    days_past_due: days_past_due,
    churn_risk_score: 0,
    last_usage_review: null,
    upsell_candidate: 0,
    notes: null
  }
}];

const billing = $('Merge Paths').item.json;
const existingResp = $input.first().json;
const existing = (existingResp && existingResp.data && existingResp.data.length > 0) ? existingResp.data[0] : null;

const payload = {
  site_registry: billing.site_registry,
  billing_motion: billing.billing_motion,
  stripe_customer_id: billing.stripe_customer_id,
  stripe_subscription_id: billing.stripe_subscription_id,
  erpnext_customer_name: billing.erpnext_customer_name,
  erpnext_subscription_name: billing.erpnext_subscription_name,
  plan_name: billing.plan_name,
  monthly_revenue: billing.monthly_revenue,
  annual_revenue: billing.annual_revenue,
  lifetime_revenue: billing.lifetime_revenue,
  billing_health: billing.billing_health,
  days_past_due: billing.days_past_due,
  churn_risk_score: billing.churn_risk_score,
  last_usage_review: billing.last_usage_review,
  upsell_candidate: billing.upsell_candidate,
  notes: billing.notes
};

return [{
  json: {
    method: existing ? 'PUT' : 'POST',
    url: existing
      ? `https://admin.sparkmojo.com/api/resource/SM Platform Billing/${existing.name}`
      : 'https://admin.sparkmojo.com/api/resource/SM Platform Billing',
    payload: payload,
    site_registry: billing.site_registry
  }
}];

const items = $input.all();
let processed = 0;
let created = 0;
let updated = 0;
let errors = [];

for (const item of items) {
  const d = item.json;
  processed++;
  if (d.error) {
    errors.push(`${d.site_registry || 'unknown'}: ${d.error}`);
  } else {
    const buildItem = $('Build Upsert Request').item;
    if (buildItem && buildItem.json && buildItem.json.method === 'POST') {
      created++;
    } else {
      updated++;
    }
  }
}

return [{
  json: {
    summary: {
      rows_processed: processed,
      created: created,
      updated: updated,
      error_count: errors.length,
      errors: errors
    }
  }
}];
